sql:
SELECT COUNT(*) 
FROM optimizations 
WHERE status = 'active';

external_knowledge:
- 'Subtractions' and '0.10%' refer to a specific tag and value indicating the type of benchmark application of interest; 
- 'Vectorization' is an optimization technique; 
- 'Hardware support' refers to whether a particular hardware configuration supports the benchmark application.

sql:
SELECT type, COUNT(*) AS optimization_count
FROM optimizations
GROUP BY type;

SELECT hardware_details
FROM hardware_support
WHERE benchmark_id = 1;
